const DISPLAY = "'Big Shoulders Display', 'IBM Plex Sans', sans-serif";
const BODY = "'IBM Plex Sans', -apple-system, BlinkMacSystemFont, system-ui, sans-serif";
const MONO = "'IBM Plex Mono', ui-monospace, monospace";

const VEH_ICONS = {
  car: IconCar, suv: IconSuv, van: IconVan, pickup: IconPickup,
  truck: IconTruck, bus: IconBus, moto: IconMoto, taxi: IconTaxi, ambulance: IconAmbulance,
  sport: IconSport, racingR: IconRacingR, racingY: IconRacingY,
};
