function PasswordChangeSheet({ t, dark, onClose }) {
  const [oldP, setOldP] = useState("");
  const [newP, setNewP] = useState("");
  const [confP, setConfP] = useState("");
  const [done, setDone] = useState(false);
  const tooShort = newP.length > 0 && newP.length < 6;
  const mismatch = confP.length > 0 && newP !== confP;
  const valid = oldP.length > 0 && newP.length >= 6 && newP === confP;
  const submit = () => { if (!valid) return; setDone(true); setTimeout(onClose, 1100); };
  return (
    <div onClick={onClose} style={{ position: "absolute", inset: 0, zIndex: 60, display: "flex",
      flexDirection: "column", justifyContent: "flex-end", background: "rgba(0,0,0,0.45)",
      backdropFilter: "blur(4px)", WebkitBackdropFilter: "blur(4px)" }}>
      <div onClick={(e) => e.stopPropagation()} style={{ background: t.glassSolid,
        borderTopLeftRadius: 28, borderTopRightRadius: 28, border: `1px solid ${t.border}`,
        borderBottom: "none", padding: "10px 18px 26px",
        backdropFilter: "blur(30px)", WebkitBackdropFilter: "blur(30px)" }}>
        <div style={{ width: 38, height: 5, borderRadius: 999, background: t.sub, opacity: 0.4, margin: "0 auto 14px" }} />
        <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 14 }}>
          <span style={{ width: 40, height: 40, borderRadius: 12, background: hexA(ACCENT, 0.16),
            color: t.accent, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
            <KeyRound size={20} />
          </span>
          <div style={{ flex: 1 }}>
            <div style={{ fontSize: 18, fontWeight: 800, fontFamily: DISPLAY }}>Changer le mot de passe</div>
            <div style={{ fontSize: 12, color: t.sub }}>Minimum 6 caractères</div>
          </div>
        </div>
        {done ? (
          <div style={{ display: "flex", alignItems: "center", gap: 10, padding: "16px 14px",
            borderRadius: 14, background: hexA(ONLINE, 0.14), color: ONLINE, fontWeight: 700, fontSize: 14 }}>
            <Check size={20} /> Mot de passe mis à jour
          </div>
        ) : (
          <>
            <Field t={t} label="Ancien mot de passe" icon={Lock} type="password" placeholder="••••••" value={oldP} onChange={setOldP} />
            <Field t={t} label="Nouveau mot de passe" icon={KeyRound} type="password" placeholder="••••••" value={newP} onChange={setNewP} />
            <Field t={t} label="Confirmer le nouveau mot de passe" icon={KeyRound} type="password" placeholder="••••••" value={confP} onChange={setConfP} />
            {(tooShort || mismatch) && (
              <div style={{ fontSize: 12, color: ALERT, fontWeight: 600, margin: "-4px 2px 10px" }}>
                {tooShort ? "Le nouveau mot de passe doit faire au moins 6 caractères." : "La confirmation ne correspond pas."}
              </div>
            )}
            <button onClick={submit} disabled={!valid} style={{
              width: "100%", padding: 14, borderRadius: 16, border: "none",
              cursor: valid ? "pointer" : "default",
              background: valid ? ACCENT : hexA(t.text, 0.12), color: valid ? LIME_ON : t.sub,
              fontSize: 15, fontWeight: 700, marginTop: 4 }}>
              Mettre à jour
            </button>
          </>
        )}
      </div>
    </div>
  );
}

