function SectionLabel({ t, children }) {
  return (
    <div style={{ fontSize: 13, fontWeight: 700, color: t.sub, padding: "0 22px 8px", fontFamily: DISPLAY, letterSpacing: 0.2 }}>{children}</div>
  );
}

function SettingRow({ t, icon: Icon, label, value, color, last, onClick, toggleOn, onToggle }) {
  const isToggle = onToggle !== undefined;
  return (
    <div onClick={isToggle ? undefined : onClick} style={{
      display: "flex", alignItems: "center", gap: 12, padding: "13px 14px",
      cursor: isToggle ? "default" : (onClick ? "pointer" : "default"),
      borderBottom: last ? "none" : `1px solid ${t.line}` }}>
      <span style={{ width: 32, height: 32, borderRadius: 9, flexShrink: 0,
        background: hexA(color || t.text, 0.16), color: color || t.text,
        display: "flex", alignItems: "center", justifyContent: "center" }}>
        <Icon size={17} />
      </span>
      <span style={{ fontSize: 14, fontWeight: 600, flex: 1 }}>{label}</span>
      {value && <span style={{ fontSize: 13, color: t.sub }}>{value}</span>}
      {isToggle
        ? <Toggle t={t} label="" on={toggleOn} set={() => onToggle()} />
        : <ChevronRight size={17} color={t.sub} />}
    </div>
  );
}

