function ShareImeiSheet({ t, dark, onClose }) {
  const imei = (VEHICLES[0]?.imei || "").replace(/\s/g, "");
  const [copied, setCopied] = useState(false);
  const copy = () => {
    try { navigator.clipboard && navigator.clipboard.writeText(imei); } catch (e) {}
    setCopied(true); setTimeout(() => setCopied(false), 1600);
  };
  return (
    <div onClick={onClose} style={{ position: "absolute", inset: 0, zIndex: 60, display: "flex",
      flexDirection: "column", justifyContent: "flex-end", background: "rgba(0,0,0,0.45)",
      backdropFilter: "blur(4px)", WebkitBackdropFilter: "blur(4px)" }}>
      <div onClick={(e) => e.stopPropagation()} style={{ background: t.glassSolid,
        borderTopLeftRadius: 28, borderTopRightRadius: 28, border: `1px solid ${t.border}`,
        borderBottom: "none", padding: "10px 18px 26px",
        backdropFilter: "blur(30px)", WebkitBackdropFilter: "blur(30px)" }}>
        <div style={{ width: 38, height: 5, borderRadius: 999, background: t.sub, opacity: 0.4, margin: "0 auto 14px" }} />
        <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 14 }}>
          <span style={{ width: 40, height: 40, borderRadius: 12, background: hexA(ACCENT, 0.16),
            color: t.accent, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
            <Share2 size={20} />
          </span>
          <div style={{ flex: 1 }}>
            <div style={{ fontSize: 18, fontWeight: 800, fontFamily: DISPLAY }}>Partager l'appareil</div>
            <div style={{ fontSize: 12, color: t.sub }}>Communiquez cet IMEI pour partager l'accès au suivi</div>
          </div>
        </div>

        <div style={{ fontSize: 11, fontWeight: 700, color: t.sub, textTransform: "uppercase",
          letterSpacing: 0.6, marginBottom: 8, paddingLeft: 2 }}>IMEI du dispositif</div>
        <div style={{ ...glassStyle(t), borderRadius: 16, padding: "16px 16px", display: "flex",
          alignItems: "center", gap: 12 }}>
          <span style={{ flex: 1, fontFamily: MONO, fontSize: 20, fontWeight: 600, letterSpacing: 1 }}>{imei}</span>
          <button onClick={copy} style={{ display: "flex", alignItems: "center", gap: 7, border: "none",
            cursor: "pointer", borderRadius: 12, padding: "10px 14px", fontSize: 13, fontWeight: 700,
            background: copied ? hexA(ONLINE, 0.18) : ACCENT, color: copied ? ONLINE : LIME_ON }}>
            {copied ? <><Check size={16} /> Copié</> : <><Copy size={16} /> Copier</>}
          </button>
        </div>
      </div>
    </div>
  );
}

function RangePickerSheet({ t, dark, onApply, onClose }) {
  const [start, setStart] = useState(null);
  const [end, setEnd] = useState(null);
  const firstDow = (new Date(2026, 5, 1).getDay() + 6) % 7;
  const cells = [];
  for (let i = 0; i < firstDow; i++) cells.push(null);
  for (let d = 1; d <= 30; d++) cells.push(d);
  const tap = (d) => {
    if (start == null || end != null) { setStart(d); setEnd(null); }
    else if (d < start) { setEnd(start); setStart(d); }
    else setEnd(d);
  };
  const inRange = (d) => start != null && end != null && d >= start && d <= end;
  const isEdge = (d) => d === start || d === end;
  const valid = start != null;
  return (
    <div onClick={onClose} style={{ position: "absolute", inset: 0, zIndex: 70, display: "flex",
      flexDirection: "column", justifyContent: "flex-end", background: "rgba(0,0,0,0.45)",
      backdropFilter: "blur(4px)", WebkitBackdropFilter: "blur(4px)" }}>
      <div onClick={(e) => e.stopPropagation()} style={{ background: t.glassSolid,
        borderTopLeftRadius: 28, borderTopRightRadius: 28, border: `1px solid ${t.border}`,
        borderBottom: "none", padding: "10px 16px 24px",
        backdropFilter: "blur(30px)", WebkitBackdropFilter: "blur(30px)" }}>
        <div style={{ width: 38, height: 5, borderRadius: 999, background: t.sub, opacity: 0.4, margin: "0 auto 14px" }} />
        <div style={{ fontSize: 17, fontWeight: 800, fontFamily: DISPLAY, marginBottom: 4 }}>Choisir un intervalle</div>
        <div style={{ fontSize: 12, color: t.sub, marginBottom: 12 }}>
          {start == null ? "Touchez le premier jour" : end == null ? "Touchez le dernier jour" : `${start} → ${end} juin 2026`}
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(7,1fr)", gap: 4, marginBottom: 6 }}>
          {["L", "M", "M", "J", "V", "S", "D"].map((d, i) => (
            <div key={i} style={{ textAlign: "center", fontSize: 11, fontWeight: 700, color: t.sub }}>{d}</div>
          ))}
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(7,1fr)", gap: 4 }}>
          {cells.map((d, i) => d === null
            ? <div key={i} />
            : (
              <button key={i} onClick={() => tap(d)} style={{
                aspectRatio: "1 / 1", borderRadius: 10, border: "none", cursor: "pointer",
                fontSize: 13, fontWeight: 600,
                background: isEdge(d) ? ACCENT : inRange(d) ? hexA(ACCENT, 0.22) : t.glass,
                color: isEdge(d) ? LIME_ON : t.text }}>{d}</button>
            ))}
        </div>
        <button onClick={() => { if (valid) { onApply({ start, end: end ?? start }); onClose(); } }}
          disabled={!valid} style={{ width: "100%", marginTop: 14, padding: 13, borderRadius: 14,
          border: "none", cursor: valid ? "pointer" : "default",
          background: valid ? ACCENT : hexA(t.text, 0.12), color: valid ? LIME_ON : t.sub,
          fontSize: 14, fontWeight: 700 }}>Valider l'intervalle</button>
      </div>
    </div>
  );
}

function KmScreen({ t, v, dark, back }) {
  const [mode, setMode] = useState("7");   // "7" | "30" | "custom"
  const [range, setRange] = useState(null); // { start, end }
  const [pickerOpen, setPickerOpen] = useState(false);
  const days = mode === "7" ? 7 : mode === "30" ? 30 : (range ? range.end - range.start + 1 : 7);
  const label = mode === "7" ? "7 derniers jours" : mode === "30" ? "30 derniers jours"
    : (range ? `${range.start} – ${range.end} juin 2026` : "Choisir un intervalle");
  const kmSeries = (veh, n) => {
    const base = KM_BY_VEHICLE[veh.id] || [0, 0, 0, 0, 0, 0, 0];
    const a = []; for (let i = 0; i < n; i++) a.push(base[i % 7]); return a;
  };
  const series = kmSeries(v, Math.min(days, 31));
  const total = kmSeries(v, days).reduce((a, b) => a + b, 0);
  const max = Math.max(...series, 1);
  const perVeh = VEHICLES.map((veh) => ({ veh, km: kmSeries(veh, days).reduce((a, b) => a + b, 0) }))
    .sort((a, b) => b.km - a.km);

  return (
    <div style={{ position: "absolute", inset: 0, paddingTop: 50, paddingBottom: 90, overflowY: "auto" }}>
      <div style={{ padding: "8px 14px 10px", display: "flex", alignItems: "center", gap: 10 }}>
        <button onClick={back} aria-label="Retour" style={iconBtn(t)}><ChevronLeft size={19} /></button>
        <div>
          <div style={{ fontSize: 24, fontWeight: 800, letterSpacing: -0.5, fontFamily: DISPLAY }}>Kilométrage</div>
          <div style={{ fontSize: 12, color: t.sub }}>{v.name}</div>
        </div>
      </div>

      {/* interval selector */}
      <div style={{ display: "flex", gap: 4, margin: "0 14px 10px", ...glassStyle(t), borderRadius: 12, padding: 3 }}>
        {[["7", "7 jours"], ["30", "30 jours"], ["custom", "Perso"]].map(([id, lbl]) => (
          <button key={id} onClick={() => { setMode(id); if (id === "custom") setPickerOpen(true); }} style={{
            flex: 1, padding: "8px", borderRadius: 9, border: "none", cursor: "pointer",
            fontSize: 13, fontWeight: mode === id ? 700 : 500,
            background: mode === id ? ACCENT : "transparent", color: mode === id ? LIME_ON : t.sub }}>
            {lbl}
          </button>
        ))}
      </div>
      <button onClick={() => setPickerOpen(true)} style={{ margin: "0 14px 14px", width: "calc(100% - 28px)",
        ...glassStyle(t), borderRadius: 12, padding: "9px 12px", display: "flex", alignItems: "center",
        gap: 8, cursor: "pointer", color: t.text }}>
        <CalendarDays size={16} color={t.accent} />
        <span style={{ fontSize: 13.5, fontWeight: 600 }}>{label}</span>
      </button>

      {/* total for the interval */}
      <div style={{ margin: "0 14px 14px", ...glassStyle(t), borderRadius: 22, padding: 16,
        display: "flex", alignItems: "flex-end", justifyContent: "space-between" }}>
        <div>
          <div style={{ fontSize: 12, color: t.sub }}>Total sur {days} jour{days > 1 ? "s" : ""}</div>
          <div style={{ fontSize: 46, fontWeight: 800, letterSpacing: -1, lineHeight: 1, fontFamily: DISPLAY }}>
            {total}<span style={{ fontSize: 18, color: t.sub, fontWeight: 600 }}> km</span>
          </div>
        </div>
        <div style={{ textAlign: "right", fontSize: 12, color: t.sub, lineHeight: 1.6 }}>
          <div>≈ {Math.round(total / days)} km / jour</div>
        </div>
      </div>

      {/* daily bars */}
      <div style={{ margin: "0 14px 14px", ...glassStyle(t), borderRadius: 22, padding: "18px 14px 14px" }}>
        <div style={{ fontSize: 11, fontWeight: 700, color: t.sub, textTransform: "uppercase",
          letterSpacing: 0.6, marginBottom: 12 }}>Km par jour</div>
        <div style={{ display: "flex", alignItems: "flex-end", gap: days > 10 ? 2 : 7, height: 140 }}>
          {series.map((km, i) => {
            const h = Math.round((km / max) * 110) + 4;
            return (
              <div key={i} style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center",
                gap: 5, height: "100%", justifyContent: "flex-end" }}>
                {days <= 7 && <span style={{ fontSize: 9.5, fontWeight: 700, color: t.sub }}>{km}</span>}
                <div style={{ width: "100%", height: h, borderRadius: days > 10 ? 3 : 7, background: ACCENT }} />
                {days <= 7 && <span style={{ fontSize: 10, color: t.sub }}>{DAYS[i % 7]}</span>}
              </div>
            );
          })}
        </div>
      </div>

      {/* per vehicle */}
      {VEHICLES.length > 1 && (
        <>
          <div style={{ fontSize: 13, fontWeight: 700, color: t.sub, padding: "4px 22px 8px",
            fontFamily: DISPLAY, letterSpacing: 0.2 }}>Par véhicule</div>
          <div style={{ margin: "0 14px", ...glassStyle(t), borderRadius: 22, overflow: "hidden" }}>
            {perVeh.map(({ veh, km }, i) => (
              <div key={veh.id} style={{ display: "flex", alignItems: "center", gap: 11, padding: "12px 14px",
                borderBottom: i === perVeh.length - 1 ? "none" : `1px solid ${t.line}`,
                background: veh.id === v.id ? hexA(ACCENT, 0.08) : "transparent" }}>
                <span style={{ width: 9, height: 9, borderRadius: "50%", background: veh.color, flexShrink: 0 }} />
                <span style={{ flex: 1, fontSize: 14, fontWeight: 600 }}>{veh.name}</span>
                <span style={{ fontSize: 15, fontWeight: 700, fontFamily: MONO }}>
                  {km}<span style={{ fontSize: 11, color: t.sub, fontWeight: 500 }}> km</span>
                </span>
              </div>
            ))}
          </div>
        </>
      )}

      {pickerOpen && (
        <RangePickerSheet t={t} dark={dark}
          onApply={(r) => { setRange(r); setMode("custom"); }}
          onClose={() => setPickerOpen(false)} />
      )}
    </div>
  );
}

function StatsScreen({ t, v, dark }) {
  const data = KM_BY_VEHICLE[v.id] || [0, 0, 0, 0, 0, 0, 0];
  const s = STATS_BY_VEHICLE[v.id] || { drive: "—", idle: "—", trips: 0, stops: 0, avg: 0, max: 0, over: 0, days: 0 };
  const [sel, setSel] = useState(6);
  const [pickDate, setPickDate] = useState(29);
  const [pickerOpen, setPickerOpen] = useState(false);
  const max = Math.max(...data, 1);
  const total = data.reduce((a, b) => a + b, 0);
  const avg = Math.round(total / 7);
  const inWeek = pickDate >= 23 && pickDate <= 29;
  const dayKm = inWeek ? data[pickDate - 23] : ((pickDate * 37) % 70);

  return (
    <div style={{ position: "absolute", inset: 0, paddingTop: 50, paddingBottom: 90, overflowY: "auto" }}>
      <div style={{ padding: "8px 18px 12px" }}>
        <div style={{ fontSize: 26, fontWeight: 800, letterSpacing: -0.5, fontFamily: DISPLAY }}>Statistiques</div>
        <div style={{ fontSize: 13, color: t.sub }}>{v.name} · kilométrage</div>
      </div>

      {/* date selector */}
      <div style={{ margin: "0 14px 14px", display: "flex", alignItems: "center", gap: 8 }}>
        <button onClick={() => setPickerOpen(true)} style={{ flex: 1, ...glassStyle(t), borderRadius: 14,
          padding: "9px 12px", display: "flex", alignItems: "center", gap: 8, cursor: "pointer",
          color: t.text }}>
          <CalendarDays size={16} color={t.accent} />
          <span style={{ fontSize: 13.5, fontWeight: 600 }}>{pickDate} juin 2026</span>
        </button>
        <button onClick={() => setPickerOpen(true)} style={ctrlBtn(t)}><CalendarDays size={17} /></button>
      </div>

      {/* selected day big stat */}
      <div style={{ margin: "0 14px 14px", ...glassStyle(t), borderRadius: 22, padding: 16,
        display: "flex", alignItems: "flex-end", justifyContent: "space-between" }}>
        <div>
          <div style={{ fontSize: 12, color: t.sub }}>{pickDate} juin 2026</div>
          <div style={{ fontSize: 46, fontWeight: 800, letterSpacing: -1, lineHeight: 1, fontFamily: DISPLAY }}>
            {dayKm}<span style={{ fontSize: 18, color: t.sub, fontWeight: 600 }}> km</span>
          </div>
        </div>
        <div style={{ textAlign: "right", fontSize: 12, color: t.sub, lineHeight: 1.7 }}>
          <div>parcourus ce jour</div>
          <div style={{ color: dayKm > avg ? ONLINE : PARKED, fontWeight: 700 }}>
            {dayKm >= avg ? "▲" : "▼"} {Math.abs(dayKm - avg)} km vs moy.
          </div>
        </div>
      </div>

      {/* bar chart — tap a day to select */}
      <div style={{ margin: "0 14px 14px", ...glassStyle(t), borderRadius: 22, padding: "18px 14px 14px" }}>
        <div style={{ display: "flex", alignItems: "flex-end", gap: 7, height: 150 }}>
          {data.map((km, i) => {
            const h = max > 0 ? Math.round((km / max) * 118) + 6 : 6;
            const on = i === sel;
            return (
              <div key={i} onClick={() => { setSel(i); setPickDate(23 + i); }} style={{ flex: 1, display: "flex",
                flexDirection: "column", alignItems: "center", gap: 6, cursor: "pointer", height: "100%",
                justifyContent: "flex-end" }}>
                <span style={{ fontSize: 9.5, fontWeight: 700, color: on ? t.accent : t.sub }}>{km}</span>
                <div style={{ width: "100%", height: h, borderRadius: 8,
                  background: on ? ACCENT : hexA(ACCENT, 0.2), transition: "all .15s" }} />
                <span style={{ fontSize: 10, fontWeight: on ? 700 : 500, color: on ? t.text : t.sub }}>{DAYS[i]}</span>
              </div>
            );
          })}
        </div>
      </div>

      {/* summary cards */}
      <div style={{ margin: "0 14px", display: "flex", gap: 10 }}>
        <Metric t={t} label="Total semaine" value={`${total}`} unit="km" />
        <Metric t={t} label="Moyenne / j" value={`${avg}`} unit="km" />
        <Metric t={t} label="Jour max" value={`${max}`} unit="km" />
      </div>

      {/* activity breakdown */}
      <div style={{ fontSize: 13, fontWeight: 700, color: t.sub, padding: "18px 18px 8px" }}>
        Activité de la semaine
      </div>
      <div style={{ margin: "0 14px", display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
        <Metric t={t} label="Temps de conduite" value={s.drive} small />
        <Metric t={t} label="Temps à l'arrêt" value={s.idle} small />
        <Metric t={t} label="Trajets" value={`${s.trips}`} />
        <Metric t={t} label="Arrêts" value={`${s.stops}`} />
        <Metric t={t} label="Vitesse moy" value={`${s.avg}`} unit="km/h" />
        <Metric t={t} label="Vitesse max" value={`${s.max}`} unit="km/h" />
        <Metric t={t} label="Excès de vitesse" value={`${s.over}`}
          valueColor={s.over > 0 ? ALERT : ONLINE} small />
        <Metric t={t} label="Jours actifs" value={`${s.days}/7`} small />
      </div>

      {pickerOpen && (
        <DatePickerSheet t={t} dark={dark} selected={pickDate}
          onSelect={(d) => { setPickDate(d); if (d >= 23 && d <= 29) setSel(d - 23); }}
          onClose={() => setPickerOpen(false)} />
      )}
    </div>
  );
}

/* ---------------------------------------------------------------- TRAJECTORY SCREEN */
function TrajectoryScreen({ t, v, dark, back, mapType, setMapType, iconFor }) {
  const TIcon = iconFor ? iconFor(v) : v.icon;
  const sat = mapType === "satellite";
  const pathRef = useRef(null);
  const [len, setLen] = useState(0);
  const [progress, setProgress] = useState(0);     // 0..1
  const [playing, setPlaying] = useState(false);
  const [speedMode, setSpeedMode] = useState("Moyen");
  const [marker, setMarker] = useState({ x: 30, y: 195 });
  const [pts, setPts] = useState({ start: { x: 30, y: 195 }, end: { x: 292, y: 56 }, parks: [] });
  const [showStops, setShowStops] = useState(true);
  const [showStart, setShowStart] = useState(true);
  const [wifiLbs, setWifiLbs] = useState(true);
  const [trajDate, setTrajDate] = useState(29);
  const [pickerOpen, setPickerOpen] = useState(false);

  // measure path + key points once
  useEffect(() => {
    const p = pathRef.current; if (!p) return;
    const L = p.getTotalLength(); setLen(L);
    const at = (f) => { const pt = p.getPointAtLength(f * L); return { x: pt.x, y: pt.y }; };
    setPts({ start: at(0), end: at(1), parks: [at(0.42), at(0.70)] });
    setMarker(at(0));
  }, []);

  // move marker with progress
  useEffect(() => {
    if (!len || !pathRef.current) return;
    const pt = pathRef.current.getPointAtLength(progress * len);
    setMarker({ x: pt.x, y: pt.y });
  }, [progress, len]);

  // playback loop
  useEffect(() => {
    if (!playing) return;
    const mult = speedMode === "Lent" ? 0.4 : speedMode === "Vite" ? 1.8 : 0.9;
    const id = setInterval(() => {
      setProgress((pr) => {
        const np = pr + 0.006 * mult;
        if (np >= 1) { setPlaying(false); return 1; }
        return np;
      });
    }, 40);
    return () => clearInterval(id);
  }, [playing, speedMode]);

  const cur = [...PLAYBACK].reverse().find((s) => s.f <= progress) || PLAYBACK[0];
  const moving = cur.speed > 0;
  const cycleSpeed = () => setSpeedMode((m) => (m === "Lent" ? "Moyen" : m === "Moyen" ? "Vite" : "Lent"));
  const replay = () => { setProgress(0); setPlaying(true); };

  return (
    <div style={{ position: "absolute", inset: 0, paddingBottom: 90, overflowY: "auto" }}>
      {/* MAP with animated route */}
      <div style={{ height: 252, position: "relative", background: mapBackground(t, sat) }}>
        <MapGrid dark={dark} sat={sat} />
        <svg viewBox="0 0 322 252" width="100%" height="252" preserveAspectRatio="xMidYMid slice"
          style={{ position: "absolute", inset: 0 }}>
          {/* base (remaining) route */}
          <path ref={pathRef} d={ROUTE_D} stroke={hexA(t.text, 0.28)} strokeWidth="4.5"
            fill="none" strokeLinecap="round" />
          {/* traveled overlay */}
          {len > 0 && (
            <path d={ROUTE_D} stroke={ONLINE} strokeWidth="4.5" fill="none" strokeLinecap="round"
              strokeDasharray={len} strokeDashoffset={len * (1 - progress)} />
          )}
          {/* stop / park markers */}
          {showStops && pts.parks.map((pk, i) => (
            <g key={i}>
              <circle cx={pk.x} cy={pk.y} r="9" fill={PARKED} stroke="#fff" strokeWidth="2.5" />
              <text x={pk.x} y={pk.y + 3.5} textAnchor="middle" fontSize="10" fontWeight="700" fill="#fff">P</text>
            </g>
          ))}
          {/* start */}
          {showStart && <circle cx={pts.start.x} cy={pts.start.y} r="7.5" fill={ACCENT} stroke="#fff" strokeWidth="2.5" />}
          {/* end */}
          <circle cx={pts.end.x} cy={pts.end.y} r="7.5" fill={ALERT} stroke="#fff" strokeWidth="2.5" />
          {/* moving marker */}
          <circle cx={marker.x} cy={marker.y} r={moving && playing ? 16 : 12}
            fill="none" stroke={ACCENT} strokeWidth="2" opacity="0.4">
            {playing && <animate attributeName="r" values="11;18;11" dur="1.4s" repeatCount="indefinite" />}
          </circle>
          <circle cx={marker.x} cy={marker.y} r="8" fill="#fff" stroke={ACCENT} strokeWidth="3" />
        </svg>

        <button onClick={back} style={{ position: "absolute", top: 52, left: 14, zIndex: 20, ...iconBtn(t) }}>
          <ChevronLeft size={19} />
        </button>
        {/* date pill */}
        <button onClick={() => setPickerOpen(true)} style={{ position: "absolute", top: 52, right: 14, zIndex: 20,
          ...glassStyle(t), borderRadius: 12, padding: "7px 11px", display: "flex", alignItems: "center",
          gap: 6, cursor: "pointer", color: t.text }}>
          <CalendarDays size={14} color={t.accent} />
          <span style={{ fontSize: 12, fontWeight: 600 }}>{trajDate} juin</span>
        </button>
        <div style={{ position: "absolute", top: 92, right: 14, zIndex: 20 }}>
          <MapTypeToggle t={t} mapType={mapType} setMapType={setMapType} />
        </div>
      </div>

      {/* LIVE READOUT + CONTROLS */}
      <div style={{ padding: "14px 14px 0", marginTop: -22, position: "relative", zIndex: 5 }}>
        <div style={{ ...glassStyle(t), borderRadius: 22, padding: 16 }}>
          {/* name + live speed */}
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <div style={{ width: 40, height: 40, borderRadius: 12, flexShrink: 0,
              background: hexA(v.color, 0.16), color: v.color,
              display: "flex", alignItems: "center", justifyContent: "center" }}>
              <TIcon size={20} />
            </div>
            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={{ fontSize: 15, fontWeight: 800 }}>{v.name}</div>
              <div style={{ fontSize: 11.5, color: t.sub }}>
                Lecture du trajet · {moving ? cur.dir : "à l'arrêt"}
              </div>
            </div>
            <div style={{ textAlign: "right" }}>
              <div style={{ fontSize: 22, fontWeight: 800, color: moving ? t.accent : t.sub,
                fontFamily: "'IBM Plex Mono', monospace", lineHeight: 1 }}>
                {cur.speed}<span style={{ fontSize: 11, color: t.sub, fontWeight: 600 }}> km/h</span>
              </div>
            </div>
          </div>

          {/* time + full address */}
          <div style={{ marginTop: 12, padding: "10px 12px", borderRadius: 14,
            background: t.glass, border: `1px solid ${t.line}` }}>
            <div style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 12,
              color: t.sub, fontFamily: "'IBM Plex Mono', monospace" }}>
              <Clock size={12} /> {String(trajDate).padStart(2, "0")}-06-2026 {cur.time}
            </div>
            <div style={{ display: "flex", alignItems: "flex-start", gap: 6, marginTop: 6 }}>
              <MapPin size={13} color={moving ? ONLINE : PARKED} style={{ flexShrink: 0, marginTop: 2 }} />
              <span style={{ fontSize: 12.5, lineHeight: 1.45 }}>{cur.addr}</span>
            </div>
          </div>

          {/* transport bar */}
          <div style={{ display: "flex", alignItems: "center", gap: 12, marginTop: 14 }}>
            <button onClick={() => setPlaying((p) => !p)} aria-label={playing ? "Pause" : "Lecture"}
              style={{ width: 42, height: 42, borderRadius: "50%", border: "none", cursor: "pointer",
                background: ALERT, color: "#fff", flexShrink: 0, display: "flex",
                alignItems: "center", justifyContent: "center",
                boxShadow: `0 6px 16px ${hexA(ACCENT, 0.5)}` }}>
              {playing ? <Pause size={19} /> : <Play size={19} style={{ marginLeft: 2 }} />}
            </button>
            <input type="range" min="0" max="1000" value={Math.round(progress * 1000)}
              onChange={(e) => setProgress(Number(e.target.value) / 1000)}
              style={{ flex: 1, accentColor: ACCENT }} />
            <button onClick={cycleSpeed} style={{ ...iconBtn(t), width: "auto", padding: "0 10px",
              height: 32, fontSize: 12, fontWeight: 700, gap: 4, color: t.accent }}>
              {speedMode}
            </button>
            <button onClick={replay} aria-label="Rediffuser" style={{ ...iconBtn(t), width: 32, height: 32 }}>
              <RotateCcw size={15} />
            </button>
          </div>

          {/* toggles */}
          <div style={{ display: "flex", justifyContent: "space-between", gap: 8, marginTop: 14,
            paddingTop: 14, borderTop: `1px solid ${t.line}` }}>
            <Toggle t={t} label="Arrêts" on={showStops} set={setShowStops} />
            <Toggle t={t} label="Départ" on={showStart} set={setShowStart} />
            <Toggle t={t} label="wifi/lbs" on={wifiLbs} set={setWifiLbs} />
          </div>
        </div>

        {/* compact summary */}
        <div style={{ display: "flex", gap: 8, marginTop: 12 }}>
          <Metric t={t} label="Distance" value="27.0" unit="km" />
          <Metric t={t} label="Durée" value="4h16" unit="" />
          <Metric t={t} label="Vit. max" value="63" unit="km/h" />
        </div>

        {/* detailed timeline (validé) */}
        <div style={{ marginTop: 16, marginBottom: 8, fontSize: 13, fontWeight: 700, color: t.sub, paddingLeft: 4 }}>
          Détail du trajet
        </div>
        <div style={{ ...glassStyle(t), borderRadius: 22, padding: "6px 14px 14px" }}>
          {TRAJ.map((e, i) => <TrajRow key={i} t={t} e={e} first={i === 0} last={i === TRAJ.length - 1} />)}
        </div>
      </div>

      {pickerOpen && (
        <DatePickerSheet t={t} dark={dark} selected={trajDate}
          onSelect={(d) => setTrajDate(d)} onClose={() => setPickerOpen(false)} />
      )}
    </div>
  );
}

function Toggle({ t, label, on, set }) {
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 7 }}>
      <span style={{ fontSize: 12, color: t.sub }}>{label}</span>
      <button onClick={() => set(!on)} aria-label={label} style={{
        width: 40, height: 24, borderRadius: 999, border: "none", cursor: "pointer", padding: 0,
        background: on ? ONLINE : hexA(t.text, 0.2), position: "relative", transition: "background .15s",
      }}>
        <span style={{ position: "absolute", top: 2, left: on ? 18 : 2, width: 20, height: 20,
          borderRadius: "50%", background: "#fff", transition: "left .15s",
          boxShadow: "0 1px 3px rgba(0,0,0,0.3)" }} />
      </button>
    </div>
  );
}

function TrajRow({ t, e, first, last }) {
  const conf = {
    start: { c: ONLINE, icon: Flag, title: "Départ", sub: e.place },
    end: { c: ALERT, icon: Flag, title: "Arrivée", sub: e.place },
    move: { c: ACCENT, icon: Navigation, title: e.place,
      sub: `${e.dist} km · ${e.avg} km/h moy · ${e.max} km/h max` },
    park: { c: PARKED, icon: Clock, title: "Stationné", sub: `${e.place} · ${e.dur}` },
  }[e.type];
  const timeLabel = e.type === "move" || e.type === "park" ? `${e.from} – ${e.to}` : e.time;

  return (
    <div style={{ display: "flex", gap: 12, paddingTop: 10, paddingBottom: 10 }}>
      {/* rail */}
      <div style={{ display: "flex", flexDirection: "column", alignItems: "center", width: 30, flexShrink: 0 }}>
        <div style={{ width: 1, height: 8, background: first ? "transparent" : t.line }} />
        <div style={{ width: 28, height: 28, borderRadius: e.type === "park" ? 8 : "50%",
          background: hexA(conf.c, 0.18), color: conf.c,
          display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
          <conf.icon size={15} />
        </div>
        <div style={{ width: 1, flex: 1, background: last ? "transparent" : t.line, minHeight: 8 }} />
      </div>
      {/* content */}
      <div style={{ flex: 1, minWidth: 0, paddingTop: 6 }}>
        <div style={{ display: "flex", alignItems: "baseline", gap: 8, justifyContent: "space-between" }}>
          <span style={{ fontSize: 14, fontWeight: 700 }}>{conf.title}</span>
          <span style={{ fontSize: 11.5, color: t.sub, fontFamily: "'IBM Plex Mono', monospace", flexShrink: 0 }}>{timeLabel}</span>
        </div>
        <div style={{ fontSize: 12, color: e.type === "park" ? PARKED : t.sub, marginTop: 2 }}>{conf.sub}</div>
      </div>
    </div>
  );
}

/* ---------------------------------------------------------------- ALARMS SCREEN */
function AlarmsScreen({ t, dark, openAlarm }) {
  const typeById = Object.fromEntries(ALARM_TYPES.map((a) => [a.id, a]));
  const [health, setHealth] = useState(DEVICE_HEALTH);
  const anomCount = health.filter((d) => d.status !== "ok").length;
  const [tab, setTab] = useState(anomCount > 0 ? "anomalies" : "alarmes");
  const [armed, setArmed] = useState(true);
  const [showSettings, setShowSettings] = useState(false);
  const [enabled, setEnabled] = useState(() => Object.fromEntries(ALARM_TYPES.map((a) => [a.id, true])));
  const [open, setOpen] = useState(() =>
    Object.fromEntries(DEVICE_HEALTH.map((d) => [d.vehicle, d.status === "problem"])));
  const resolve = (vehicle, idx) => setHealth((hs) => hs.map((d) => {
    if (d.vehicle !== vehicle) return d;
    const anomalies = d.anomalies.filter((_, i) => i !== idx);
    return { ...d, anomalies, status: anomalies.length === 0 ? "ok" : d.status };
  }));

  const ST = {
    ok: { dot: ONLINE, label: "OK", sub: "connecté · alimentation et signal normaux" },
    check: { dot: PARKED, label: "À vérifier", sub: null },
    problem: { dot: ALERT, label: "Problème · action requise", sub: null },
  };

  return (
    <div style={{ position: "absolute", inset: 0, paddingTop: 50, paddingBottom: 90, overflowY: "auto" }}>
      <div style={{ padding: "8px 18px 10px", display: "flex", alignItems: "center", gap: 12 }}>
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 26, fontWeight: 800, letterSpacing: -0.5, fontFamily: DISPLAY }}>Alarmes</div>
          <div style={{ fontSize: 13, color: t.sub }}>
            {tab === "anomalies"
              ? (anomCount > 0 ? `${anomCount} dispositif(s) à corriger` : "Tous les dispositifs vont bien")
              : `${ALARM_EVENTS.length} événements récents`}
          </div>
        </div>
        <button onClick={() => setShowSettings(true)} aria-label="Réglages des alertes" style={ctrlBtn(t)}>
          <Settings size={18} />
        </button>
      </div>

      {/* segmented tabs */}
      <div style={{ display: "flex", gap: 4, margin: "0 16px 12px", ...glassStyle(t),
        borderRadius: 12, padding: 3 }}>
        {[["alarmes", "Alarmes"], ["anomalies", "Anomalies"]].map(([id, lbl]) => (
          <button key={id} onClick={() => setTab(id)} style={{
            flex: 1, padding: "8px", borderRadius: 9, border: "none", cursor: "pointer",
            fontSize: 13, fontWeight: tab === id ? 700 : 500, position: "relative",
            background: tab === id ? ACCENT : "transparent",
            color: tab === id ? LIME_ON : t.sub,
            display: "flex", alignItems: "center", justifyContent: "center", gap: 6 }}>
            {lbl}
            {id === "anomalies" && anomCount > 0 && (
              <span style={{ background: tab === id ? "#fff" : ALERT, color: tab === id ? ALERT : "#fff",
                fontSize: 10, fontWeight: 800, minWidth: 16, height: 16, borderRadius: 999,
                display: "inline-flex", alignItems: "center", justifyContent: "center", padding: "0 4px" }}>
                {anomCount}
              </span>
            )}
          </button>
        ))}
      </div>

      {/* master notifications */}
      <div style={{ margin: "0 14px 14px", ...glassStyle(t), borderRadius: 20, padding: 13,
        display: "flex", alignItems: "center", gap: 12 }}>
        <span style={{ width: 38, height: 38, borderRadius: 12, flexShrink: 0,
          background: hexA(armed ? ONLINE : OFFLINE, 0.16), color: armed ? ONLINE : OFFLINE,
          display: "flex", alignItems: "center", justifyContent: "center" }}>
          <Bell size={19} />
        </span>
        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ fontSize: 14, fontWeight: 700 }}>{armed ? "Notifications armées" : "Notifications désarmées"}</div>
          <div style={{ fontSize: 11.5, color: t.sub }}>
            {armed ? "Alertes actives sur ce téléphone" : "Aucune alerte ne sera reçue"}
          </div>
        </div>
        <button onClick={() => setArmed((a) => !a)} aria-label="Armer / Désarmer" style={{
          width: 52, height: 30, borderRadius: 999, border: "none", cursor: "pointer", padding: 0,
          background: armed ? ONLINE : hexA(t.text, 0.2), position: "relative", transition: "background .15s" }}>
          <span style={{ position: "absolute", top: 3, left: armed ? 25 : 3, width: 24, height: 24,
            borderRadius: "50%", background: "#fff", transition: "left .15s", boxShadow: "0 1px 3px rgba(0,0,0,0.3)" }} />
        </button>
      </div>

      {/* ===== ANOMALIES TAB ===== */}
      {tab === "anomalies" && (
        <div style={{ padding: "0 14px", display: "flex", flexDirection: "column", gap: 10 }}>
          {health.map((d) => {
            const st = ST[d.status];
            const isOpen = open[d.vehicle];
            const summary = d.status === "ok" ? st.sub : (typeById[d.anomalies[0]?.type]?.label || st.label);
            return (
              <div key={d.vehicle} style={{ ...glassStyle(t), borderRadius: 18, overflow: "hidden",
                border: `1px solid ${d.status === "ok" ? t.border : hexA(st.dot, 0.4)}`,
                background: d.status === "ok" ? t.glass : hexA(st.dot, 0.07) }}>
                <div onClick={() => d.status !== "ok" && setOpen((o) => ({ ...o, [d.vehicle]: !o[d.vehicle] }))}
                  style={{ display: "flex", alignItems: "center", gap: 11, padding: 13,
                    cursor: d.status === "ok" ? "default" : "pointer" }}>
                  <span style={{ width: 11, height: 11, borderRadius: "50%", flexShrink: 0,
                    background: st.dot, boxShadow: `0 0 0 4px ${hexA(st.dot, 0.18)}` }} />
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontSize: 15, fontWeight: 700 }}>{d.vehicle}</div>
                    <div style={{ fontSize: 12, color: st.dot, marginTop: 1, whiteSpace: "nowrap",
                      overflow: "hidden", textOverflow: "ellipsis" }}>
                      {st.label}{summary && d.status !== "ok" ? ` · ${summary}` : ""}
                      {d.status === "ok" ? ` · ${st.sub}` : ""}
                    </div>
                  </div>
                  {d.status !== "ok" && (
                    <span style={{ color: t.sub, fontSize: 16, flexShrink: 0 }}>{isOpen ? "⌄" : "›"}</span>
                  )}
                </div>

                {isOpen && d.anomalies.length > 0 && (
                  <div style={{ borderTop: `1px solid ${t.line}`, padding: "4px 13px 13px" }}>
                    {d.anomalies.map((an, i) => {
                      const ty = typeById[an.type];
                      return (
                        <div key={i} style={{ display: "flex", gap: 10, paddingTop: 12 }}>
                          <span style={{ width: 30, height: 30, borderRadius: 9, flexShrink: 0,
                            background: hexA(ty.color, 0.18), color: ty.color,
                            display: "flex", alignItems: "center", justifyContent: "center" }}>
                            <ty.icon size={15} />
                          </span>
                          <div style={{ flex: 1, minWidth: 0 }}>
                            <div style={{ fontSize: 13.5, fontWeight: 700 }}>{ty.label}</div>
                            <div style={{ fontSize: 12, color: t.sub, marginTop: 2, lineHeight: 1.4 }}>{an.cause}</div>
                            <button onClick={() => resolve(d.vehicle, i)} style={{ marginTop: 8, fontSize: 12, fontWeight: 700, color: t.accent,
                              background: hexA(ACCENT, 0.14), border: "none", borderRadius: 999,
                              padding: "5px 11px", cursor: "pointer" }}>{an.action} →</button>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {/* ===== ALARMES (events) TAB ===== */}
      {tab === "alarmes" && (
        <div style={{ padding: "0 14px", display: "flex", flexDirection: "column", gap: 10 }}>
          {ALARM_EVENTS.map((e, i) => {
            const ty = typeById[e.type];
            const off = !enabled[e.type] || !armed;
            return (
              <div key={i} onClick={() => openAlarm(e)} style={{ ...glassStyle(t), borderRadius: 16, padding: 13,
                display: "flex", alignItems: "center", gap: 12, opacity: off ? 0.45 : 1, cursor: "pointer" }}>
                <span style={{ width: 40, height: 40, borderRadius: 12, flexShrink: 0,
                  background: hexA(ty.color, 0.16), color: ty.color,
                  display: "flex", alignItems: "center", justifyContent: "center" }}>
                  <ty.icon size={20} />
                </span>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ fontSize: 14, fontWeight: 700 }}>{ty.label}</div>
                  <div style={{ fontSize: 12, color: t.sub, whiteSpace: "nowrap", overflow: "hidden",
                    textOverflow: "ellipsis" }}>{e.vehicle} · {e.detail}</div>
                </div>
                <div style={{ display: "flex", flexDirection: "column", alignItems: "flex-end", gap: 3, flexShrink: 0 }}>
                  <span style={{ fontSize: 11, color: t.sub }}>{e.time}</span>
                  <span style={{ display: "flex", alignItems: "center", gap: 3, fontSize: 10.5,
                    fontWeight: 700, color: t.accent }}><MapPin size={11} /> Voir</span>
                </div>
              </div>
            );
          })}
          <div style={{ marginTop: 2, background: t.glass, border: `1px dashed ${t.border}`,
            borderRadius: 16, padding: 12, opacity: 0.65 }}>
            <div style={{ fontSize: 12, fontWeight: 700, color: t.sub }}>Capteurs optionnels — non installés</div>
            <div style={{ fontSize: 11.5, color: t.sub, marginTop: 4 }}>Bouton SOS · Choc / collision · Chute de carburant</div>
          </div>
        </div>
      )}

      {showSettings && (
        <AlarmSettingsSheet t={t} dark={dark} enabled={enabled} setEnabled={setEnabled}
          onClose={() => setShowSettings(false)} />
      )}
    </div>
  );
}

function AlarmSettingsSheet({ t, dark, enabled, setEnabled, onClose }) {
  const toggle = (id) => setEnabled((m) => ({ ...m, [id]: !m[id] }));
  return (
    <div style={{ position: "absolute", inset: 0, zIndex: 60, display: "flex", flexDirection: "column",
      justifyContent: "flex-end", background: "rgba(0,0,0,0.45)",
      backdropFilter: "blur(4px)", WebkitBackdropFilter: "blur(4px)" }} onClick={onClose}>
      <div onClick={(e) => e.stopPropagation()} style={{
        background: t.glassSolid, borderTopLeftRadius: 28, borderTopRightRadius: 28,
        border: `1px solid ${t.border}`, borderBottom: "none", padding: "10px 14px 22px",
        backdropFilter: "blur(30px)", WebkitBackdropFilter: "blur(30px)", maxHeight: 540, overflowY: "auto" }}>
        <div style={{ width: 38, height: 5, borderRadius: 999, background: t.sub, opacity: 0.4, margin: "0 auto 14px" }} />
        <div style={{ fontSize: 18, fontWeight: 800, padding: "0 4px 2px", fontFamily: DISPLAY }}>Réglages des alertes</div>
        <div style={{ fontSize: 12, color: t.sub, padding: "0 4px 12px" }}>Active ou désactive chaque type d'un clic.</div>
        {[["event", "Alarmes (événements)"], ["anomaly", "Anomalies (dispositif)"]].map(([cat, title]) => (
          <div key={cat}>
            <div style={{ fontSize: 12, fontWeight: 700, color: t.sub, padding: "10px 4px 4px" }}>{title}</div>
            {ALARM_TYPES.filter((a) => a.cat === cat).map((a) => (
              <div key={a.id} style={{ display: "flex", alignItems: "center", gap: 12, padding: "10px 6px",
                borderBottom: `1px solid ${t.line}` }}>
                <span style={{ width: 34, height: 34, borderRadius: 10, flexShrink: 0,
                  background: hexA(a.color, 0.16), color: a.color,
                  display: "flex", alignItems: "center", justifyContent: "center" }}>
                  <a.icon size={17} />
                </span>
                <span style={{ flex: 1, fontSize: 14, fontWeight: 600 }}>{a.label}</span>
                <button onClick={() => toggle(a.id)} aria-label={a.label} style={{
                  width: 44, height: 26, borderRadius: 999, border: "none", cursor: "pointer", padding: 0,
                  background: enabled[a.id] ? ONLINE : hexA(t.text, 0.2), position: "relative", transition: "background .15s" }}>
                  <span style={{ position: "absolute", top: 2, left: enabled[a.id] ? 20 : 2, width: 22, height: 22,
                    borderRadius: "50%", background: "#fff", transition: "left .15s",
                    boxShadow: "0 1px 3px rgba(0,0,0,0.3)" }} />
                </button>
              </div>
            ))}
          </div>
        ))}
      </div>
    </div>
  );
}

function PasswordSheet({ t, dark, title, note, confirmLabel, danger, onConfirm, onClose }) {
  return (
    <div style={{ position: "absolute", inset: 0, zIndex: 60, display: "flex", flexDirection: "column",
      justifyContent: "flex-end", background: "rgba(0,0,0,0.45)",
      backdropFilter: "blur(4px)", WebkitBackdropFilter: "blur(4px)" }} onClick={onClose}>
      <div onClick={(e) => e.stopPropagation()} style={{
        background: t.glassSolid, borderTopLeftRadius: 28, borderTopRightRadius: 28,
        border: `1px solid ${t.border}`, borderBottom: "none", padding: "10px 18px 26px",
        backdropFilter: "blur(30px)", WebkitBackdropFilter: "blur(30px)" }}>
        <div style={{ width: 38, height: 5, borderRadius: 999, background: t.sub, opacity: 0.4, margin: "0 auto 14px" }} />
        <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 2 }}>
          <span style={{ width: 40, height: 40, borderRadius: 12, flexShrink: 0,
            background: hexA(danger ? ALERT : ACCENT, 0.16), color: danger ? ALERT : ACCENT,
            display: "flex", alignItems: "center", justifyContent: "center" }}>
            {danger ? <Lock size={20} /> : <Power size={20} />}
          </span>
          <div style={{ flex: 1 }}>
            <div style={{ fontSize: 18, fontWeight: 800, fontFamily: DISPLAY }}>{title}</div>
            <div style={{ fontSize: 12, color: t.sub }}>Confirme avec le mot de passe du compte</div>
          </div>
        </div>
        {note && (
          <div style={{ display: "flex", gap: 8, alignItems: "flex-start", margin: "12px 0 4px",
            padding: "10px 12px", borderRadius: 12, background: hexA(PARKED, 0.14) }}>
            <AlertTriangle size={16} color={PARKED} style={{ flexShrink: 0, marginTop: 1 }} />
            <span style={{ fontSize: 12, color: t.text, lineHeight: 1.45 }}>{note}</span>
          </div>
        )}
        <div style={{ marginTop: 10 }}>
          <Field t={t} label="Mot de passe du compte" icon={KeyRound} placeholder="••••••" type="password" />
        </div>
        <button onClick={onConfirm} style={{
          width: "100%", padding: 14, borderRadius: 16, border: "none", cursor: "pointer",
          background: danger ? ALERT : ACCENT, color: danger ? "#fff" : LIME_ON, fontSize: 15, fontWeight: 700, marginTop: 4,
          boxShadow: `0 8px 20px ${hexA(danger ? ALERT : ACCENT, 0.45)}` }}>
          {confirmLabel}
        </button>
      </div>
    </div>
  );
}

/* ---------------------------------------------------------------- HELPERS */
function GeofenceScreen({ t, v, dark, mapType, setMapType, back }) {
  const sat = mapType === "satellite";
  const mapRef = useRef(null);
  const [view, setView] = useState("list"); // list | edit
  const [mode, setMode] = useState("polygon");
  const [points, setPoints] = useState([]);
  const [center, setCenter] = useState(null);
  const [radius, setRadius] = useState(70);
  const [name, setName] = useState("Zone domicile");
  const [zones, setZones] = useState([
    { id: 1, name: "Entrepôt Rufisque", type: "polygon", on: true },
    { id: 2, name: "Garage Plateau", type: "circle", on: false },
  ]);

  const onMapClick = (e) => {
    const r = mapRef.current.getBoundingClientRect();
    const x = Math.round(e.clientX - r.left);
    const y = Math.round(e.clientY - r.top);
    if (mode === "polygon") setPoints((p) => [...p, { x, y }]);
    else setCenter({ x, y });
  };
  const polyD = points.length
    ? "M " + points.map((p) => `${p.x} ${p.y}`).join(" L ") + (points.length > 2 ? " Z" : "")
    : "";
  const canSave = (mode === "polygon" && points.length >= 3) || (mode === "circle" && !!center);
  const reset = () => { setPoints([]); setCenter(null); };
  const save = () => {
    if (!canSave) return;
    setZones((z) => [{ id: Date.now(), name: name || `Zone ${z.length + 1}`, type: mode, on: true }, ...z]);
    reset();
    setView("list");
  };

  /* ----- LIST VIEW (default) ----- */
  if (view === "list") {
    return (
      <div style={{ position: "absolute", inset: 0, paddingBottom: 90, overflowY: "auto" }}>
        <div style={{ height: 220, position: "relative", background: mapBackground(t, sat) }}>
          <MapGrid dark={dark} sat={sat} />
          <svg width="100%" height="220" style={{ position: "absolute", inset: 0, pointerEvents: "none" }}>
            <path d="M70 70 L150 55 L185 120 L120 160 L60 130 Z"
              fill={hexA(ACCENT, 0.18)} stroke={ACCENT} strokeWidth="2.5" strokeLinejoin="round" />
            <circle cx="245" cy="120" r="42" fill={hexA(PARKED, 0.16)} stroke={PARKED} strokeWidth="2.5" />
          </svg>
          <button onClick={back} style={{ position: "absolute", top: 52, left: 14, zIndex: 20, ...iconBtn(t) }}>
            <ChevronLeft size={19} />
          </button>
          <button onClick={() => { reset(); setView("edit"); }} aria-label="Ajouter une zone"
            style={{ position: "absolute", top: 52, right: 14, zIndex: 20, width: 42, height: 42,
              borderRadius: 14, border: "none", cursor: "pointer", background: ACCENT, color: LIME_ON,
              display: "flex", alignItems: "center", justifyContent: "center",
              boxShadow: `0 6px 16px ${hexA(ACCENT, 0.5)}` }}>
            <Plus size={22} />
          </button>
          <div style={{ position: "absolute", top: 104, right: 14, zIndex: 20 }}>
            <MapTypeToggle t={t} mapType={mapType} setMapType={setMapType} />
          </div>
        </div>

        <div style={{ padding: "14px 14px 0" }}>
          <div style={{ fontSize: 20, fontWeight: 800, marginBottom: 2, fontFamily: DISPLAY }}>Géofence</div>
          <div style={{ fontSize: 12, color: t.sub, marginBottom: 14 }}>{v.name} · zones de surveillance</div>

          <SectionLabel t={t}>Zones enregistrées</SectionLabel>
          {zones.length === 0 ? (
            <div style={{ ...glassStyle(t), borderRadius: 22, padding: "22px 16px", textAlign: "center",
              color: t.sub, fontSize: 13 }}>
              Aucune zone. Touche « + » pour en créer une.
            </div>
          ) : (
            <div style={{ ...glassStyle(t), borderRadius: 22, overflow: "hidden" }}>
              {zones.map((z, i) => (
                <div key={z.id} style={{ display: "flex", alignItems: "center", gap: 10, padding: "13px 14px",
                  borderBottom: i === zones.length - 1 ? "none" : `1px solid ${t.line}` }}>
                  <span style={{ width: 32, height: 32, borderRadius: 9, flexShrink: 0,
                    background: hexA(z.type === "circle" ? PARKED : ACCENT, 0.16),
                    color: z.type === "circle" ? PARKED : ACCENT,
                    display: "flex", alignItems: "center", justifyContent: "center" }}>
                    <Fence size={16} />
                  </span>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontSize: 14, fontWeight: 600 }}>{z.name}</div>
                    <div style={{ fontSize: 11.5, color: t.sub }}>
                      {z.type === "circle" ? "Cercle" : "Zone personnalisée"}
                    </div>
                  </div>
                  <Toggle t={t} label="" on={z.on}
                    set={(val) => setZones((arr) => arr.map((x) => x.id === z.id ? { ...x, on: val } : x))} />
                  <button onClick={() => setZones((arr) => arr.filter((x) => x.id !== z.id))}
                    aria-label="Supprimer la zone" style={{ ...iconBtn(t), width: 30, height: 30 }}>
                    <X size={15} />
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    );
  }

  /* ----- EDIT VIEW (drawing) ----- */
  return (
    <div style={{ position: "absolute", inset: 0, paddingBottom: 90, overflowY: "auto" }}>
      <div ref={mapRef} onClick={onMapClick}
        style={{ height: 300, position: "relative", background: mapBackground(t, sat), cursor: "crosshair" }}>
        <MapGrid dark={dark} sat={sat} />
        <svg width="100%" height="300" style={{ position: "absolute", inset: 0, pointerEvents: "none" }}>
          {mode === "polygon" && points.length > 0 && (
            <g>
              <path d={polyD} fill={hexA(ACCENT, 0.18)} stroke={ACCENT} strokeWidth="2.5" strokeLinejoin="round" />
              {points.map((p, i) => (
                <circle key={i} cx={p.x} cy={p.y} r="5" fill="#fff" stroke={ACCENT} strokeWidth="2.5" />
              ))}
            </g>
          )}
          {mode === "circle" && center && (
            <g>
              <circle cx={center.x} cy={center.y} r={radius} fill={hexA(ACCENT, 0.18)} stroke={ACCENT} strokeWidth="2.5" />
              <circle cx={center.x} cy={center.y} r="5" fill="#fff" stroke={ACCENT} strokeWidth="2.5" />
            </g>
          )}
        </svg>

        <button onClick={(e) => { e.stopPropagation(); reset(); setView("list"); }}
          style={{ position: "absolute", top: 52, left: 14, zIndex: 20, ...iconBtn(t) }}>
          <ChevronLeft size={19} />
        </button>
        <div onClick={(e) => e.stopPropagation()} style={{ position: "absolute", top: 52, right: 14, zIndex: 20 }}>
          <MapTypeToggle t={t} mapType={mapType} setMapType={setMapType} />
        </div>
        <div style={{ position: "absolute", left: 14, top: 96, zIndex: 20, ...glassStyle(t),
          borderRadius: 10, padding: "6px 10px", fontSize: 11.5, color: t.sub, maxWidth: 210 }}>
          {mode === "polygon"
            ? "Touche la carte pour poser les sommets et fermer la zone"
            : "Touche la carte pour placer le centre du cercle"}
        </div>
      </div>

      <div style={{ padding: "14px 14px 0" }}>
        <div style={{ fontSize: 20, fontWeight: 800, marginBottom: 12, fontFamily: DISPLAY }}>Nouvelle zone</div>

        <div style={{ display: "flex", gap: 6, ...glassStyle(t), borderRadius: 13, padding: 4, marginBottom: 12 }}>
          {[["polygon", "Zone personnalisée"], ["circle", "Cercle"]].map(([id, lbl]) => (
            <button key={id} onClick={() => { setMode(id); reset(); }} style={{
              flex: 1, padding: "9px 8px", borderRadius: 10, border: "none", cursor: "pointer",
              fontSize: 13, fontWeight: 600,
              background: mode === id ? ACCENT : "transparent", color: mode === id ? LIME_ON : t.text }}>
              {lbl}
            </button>
          ))}
        </div>

        {mode === "circle" && (
          <div style={{ ...glassStyle(t), borderRadius: 14, padding: "10px 14px", marginBottom: 12,
            display: "flex", alignItems: "center", gap: 12 }}>
            <span style={{ fontSize: 12, color: t.sub, whiteSpace: "nowrap" }}>Rayon</span>
            <input type="range" min="20" max="140" step="1" value={radius}
              onChange={(e) => setRadius(Number(e.target.value))} style={{ flex: 1, accentColor: ACCENT }} />
            <span style={{ fontSize: 13, fontWeight: 700, fontFamily: "'IBM Plex Mono', monospace" }}>
              {Math.round(radius * 5)} m
            </span>
          </div>
        )}

        <div style={{ marginBottom: 12 }}>
          <div style={{ fontSize: 12, fontWeight: 600, color: t.sub, marginBottom: 6, paddingLeft: 2 }}>Nom de la zone</div>
          <div style={{ ...glassStyle(t), borderRadius: 14, padding: "0 12px", display: "flex",
            alignItems: "center", gap: 10, height: 48 }}>
            <Fence size={18} color={t.sub} />
            <input value={name} onChange={(e) => setName(e.target.value)} placeholder="Zone domicile"
              style={{ flex: 1, background: "transparent", border: "none", outline: "none", color: t.text, fontSize: 15 }} />
          </div>
        </div>

        <div style={{ display: "flex", gap: 8, marginBottom: 18 }}>
          <button onClick={reset} style={{ ...iconBtn(t), width: "auto", height: 44, flex: 1, gap: 8,
            fontSize: 14, fontWeight: 600 }}>
            <RotateCcw size={16} /> Effacer
          </button>
          <button onClick={save} disabled={!canSave} style={{
            flex: 2, height: 44, borderRadius: 14, border: "none",
            cursor: canSave ? "pointer" : "default",
            background: canSave ? ACCENT : hexA(t.text, 0.12),
            color: canSave ? LIME_ON : t.sub, fontSize: 14, fontWeight: 700,
            display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}>
            <Check size={17} /> Enregistrer la zone
          </button>
        </div>
      </div>
    </div>
  );
}

function EditableRow({ t, icon: Icon, label, value, mono, last, onChange }) {
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 12, padding: "10px 12px",
      borderBottom: last ? "none" : `1px solid ${t.line}` }}>
      <Icon size={17} color={t.sub} style={{ flexShrink: 0 }} />
      <span style={{ fontSize: 13, color: t.sub, flexShrink: 0 }}>{label}</span>
      <input value={value} onChange={(e) => onChange(e.target.value)}
        style={{ marginLeft: "auto", textAlign: "right", background: "transparent",
          border: "none", borderBottom: `1px dashed ${t.border}`, outline: "none",
          color: t.text, fontSize: 13, fontWeight: 600, width: "52%",
          fontFamily: mono ? "'IBM Plex Mono', monospace" : "inherit" }} />
    </div>
  );
}

function DatePickerSheet({ t, dark, selected, onSelect, onClose }) {
  const firstDow = (new Date(2026, 5, 1).getDay() + 6) % 7; // Monday = 0
  const cells = [];
  for (let i = 0; i < firstDow; i++) cells.push(null);
  for (let d = 1; d <= 30; d++) cells.push(d);
  return (
    <div onClick={onClose} style={{ position: "absolute", inset: 0, zIndex: 70, display: "flex",
      flexDirection: "column", justifyContent: "flex-end", background: "rgba(0,0,0,0.45)",
      backdropFilter: "blur(4px)", WebkitBackdropFilter: "blur(4px)" }}>
      <div onClick={(e) => e.stopPropagation()} style={{ background: t.glassSolid,
        borderTopLeftRadius: 28, borderTopRightRadius: 28, border: `1px solid ${t.border}`,
        borderBottom: "none", padding: "10px 16px 26px",
        backdropFilter: "blur(30px)", WebkitBackdropFilter: "blur(30px)" }}>
        <div style={{ width: 38, height: 5, borderRadius: 999, background: t.sub, opacity: 0.4, margin: "0 auto 14px" }} />
        <div style={{ fontSize: 17, fontWeight: 800, marginBottom: 12, fontFamily: DISPLAY }}>Juin 2026</div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(7,1fr)", gap: 4, marginBottom: 6 }}>
          {["L", "M", "M", "J", "V", "S", "D"].map((d, i) => (
            <div key={i} style={{ textAlign: "center", fontSize: 11, fontWeight: 700, color: t.sub }}>{d}</div>
          ))}
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(7,1fr)", gap: 4 }}>
          {cells.map((d, i) => d === null
            ? <div key={i} />
            : (
              <button key={i} onClick={() => { onSelect(d); onClose(); }} style={{
                aspectRatio: "1 / 1", borderRadius: 10, border: "none", cursor: "pointer",
                fontSize: 13, fontWeight: 600,
                background: d === selected ? ACCENT : t.glass,
                color: d === selected ? LIME_ON : t.text }}>{d}</button>
            ))}
        </div>
      </div>
    </div>
  );
}

function AlarmLocationScreen({ t, dark, alarm, mapType, setMapType, back }) {
  const sat = mapType === "satellite";
  const ty = ALARM_TYPES.find((a) => a.id === alarm.type);
  return (
    <div style={{ position: "absolute", inset: 0, overflowY: "auto", background: t.bg }}>
      {/* header */}
      <div style={{ paddingTop: 50, padding: "50px 14px 8px", display: "flex", alignItems: "center", gap: 10 }}>
        <button onClick={back} style={{ ...iconBtn(t), width: 38, height: 38 }}><ChevronLeft size={19} /></button>
        <div style={{ fontSize: 17, fontWeight: 800, fontFamily: DISPLAY }}>Emplacement de l'alarme</div>
      </div>
      {/* address banner */}
      <div style={{ margin: "2px 14px 10px", ...glassStyle(t), borderRadius: 14, padding: "10px 12px",
        display: "flex", gap: 8, alignItems: "flex-start" }}>
        <MapPin size={15} color={t.accent} style={{ flexShrink: 0, marginTop: 1 }} />
        <div style={{ fontSize: 12.5, color: t.text, lineHeight: 1.45 }}>{alarm.addr}</div>
      </div>

      {/* map */}
      <div style={{ position: "relative", height: 420, margin: "0 14px 16px", borderRadius: 20,
        overflow: "hidden", background: mapBackground(t, sat), border: `1px solid ${t.border}` }}>
        <MapGrid dark={dark} sat={sat} />
        <div style={{ position: "absolute", top: 10, right: 10, zIndex: 20 }}>
          <MapTypeToggle t={t} mapType={mapType} setMapType={setMapType} />
        </div>

        {/* popup card */}
        <div style={{ position: "absolute", left: "50%", top: 40, transform: "translateX(-50%)",
          width: 232, background: dark ? "#1c1d26" : "#fff", borderRadius: 14,
          padding: "11px 13px", boxShadow: "0 12px 30px rgba(0,0,0,0.4)", zIndex: 16 }}>
          <button onClick={back} aria-label="Fermer" style={{ position: "absolute", top: 7, right: 7,
            border: "none", background: "transparent", color: dark ? "#aaa" : "#888", cursor: "pointer", padding: 2 }}>
            <X size={15} />
          </button>
          <div style={{ fontSize: 12.5, lineHeight: 1.7, color: dark ? "#fff" : "#111" }}>
            <div><b>Nom :</b> {alarm.vehicle}</div>
            <div><b>Statut :</b> {alarm.statusText} {alarm.speed.toFixed ? alarm.speed.toFixed(1) : alarm.speed} km/h</div>
            <div><b>Signal :</b> {alarm.dt}</div>
            <div><b>Temps :</b> {alarm.dt}</div>
          </div>
          {/* pointer */}
          <div style={{ position: "absolute", bottom: -7, left: "50%", transform: "translateX(-50%) rotate(45deg)",
            width: 14, height: 14, background: dark ? "#1c1d26" : "#fff" }} />
        </div>

        {/* alarm marker */}
        <div style={{ position: "absolute", left: "50%", top: 190, transform: "translate(-50%,-50%)", zIndex: 14 }}>
          <div style={{ width: 42, height: 42, borderRadius: "50%", background: ALERT,
            border: "3px solid #fff", display: "flex", alignItems: "center", justifyContent: "center",
            color: "#fff", boxShadow: `0 6px 18px ${hexA(ALERT, 0.6)}` }}>
            {ty ? <ty.icon size={20} /> : <Bell size={20} />}
          </div>
          <span style={{ position: "absolute", left: "50%", top: "50%", width: 60, height: 60,
            marginLeft: -30, marginTop: -30, borderRadius: "50%", border: `2px solid ${ALERT}`,
            opacity: 0.5, animation: "kpulse 1.8s ease-out infinite" }} />
        </div>

        {/* coords chip */}
        <div style={{ position: "absolute", bottom: 10, left: 10, ...glassStyle(t), borderRadius: 10,
          padding: "5px 9px", fontSize: 11, fontFamily: "'IBM Plex Mono', monospace", color: t.sub, zIndex: 16 }}>
          {alarm.lat}, {alarm.lng}
        </div>
      </div>
    </div>
  );
}

const VEH_ICON_LABELS = {
  car: "Voiture", suv: "SUV", van: "Fourgon", pickup: "Pickup", truck: "Camion",
  bus: "Bus", moto: "Moto", taxi: "Taxi", ambulance: "Ambulance",
  sport: "Sport", racingR: "Sport rouge", racingY: "Sport jaune",
};

function IconPickerSheet({ t, dark, current, color, onPick, onClose }) {
  return (
    <div style={{ position: "absolute", inset: 0, zIndex: 70, background: t.bg,
      display: "flex", flexDirection: "column" }}>
      <div style={{ padding: "8px 14px 12px", display: "flex", alignItems: "center", gap: 10,
        borderBottom: `1px solid ${t.line}` }}>
        <button onClick={onClose} aria-label="Retour" style={iconBtn(t)}><ChevronLeft size={19} /></button>
        <div>
          <div style={{ fontSize: 22, fontWeight: 800, letterSpacing: -0.5, fontFamily: DISPLAY }}>Icône du véhicule</div>
          <div style={{ fontSize: 12, color: t.sub }}>Choisis l'icône affichée sur la carte</div>
        </div>
      </div>
      <div style={{ flex: 1, overflowY: "auto", padding: 16 }}>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 12 }}>
          {VEH_ICON_LIST.map((k) => {
            const Ic = VEH_ICONS[k];
            const on = k === current;
            return (
              <button key={k} onClick={() => onPick(k)} style={{
                borderRadius: 16, cursor: "pointer", padding: "16px 8px 11px", position: "relative",
                border: on ? `2px solid ${t.accent}` : `1px solid ${t.border}`,
                background: on ? hexA(t.accent, 0.12) : t.glass,
                display: "flex", flexDirection: "column", alignItems: "center", gap: 9 }}>
                {on && (
                  <span style={{ position: "absolute", top: 8, right: 8, width: 18, height: 18, borderRadius: "50%",
                    background: t.accent, color: LIME_ON, display: "flex", alignItems: "center", justifyContent: "center" }}>
                    <Check size={12} />
                  </span>
                )}
                <Ic size={52} />
                <span style={{ fontSize: 12, fontWeight: 600, color: on ? t.text : t.sub }}>{VEH_ICON_LABELS[k] || k}</span>
              </button>
            );
          })}
        </div>
      </div>
    </div>
  );
}

function CommandToast({ t, cmd, onClose }) {
  useEffect(() => {
    if (cmd.state === "pending") return;
    const id = setTimeout(onClose, 2600);
    return () => clearTimeout(id);
  }, [cmd.state]);

  const meta = {
    pending: { color: t.accent, icon: RotateCcw, title: "Envoi de la commande…", spin: true },
    success: { color: ONLINE, icon: Check, title: "Commande envoyée au boîtier" },
    offline: { color: ALERT, icon: WifiOff, title: "GPS hors ligne — non transmise" },
    error: { color: ALERT, icon: AlertTriangle, title: "Échec de l'envoi" },
  }[cmd.state];
  const Ic = meta.icon;

  return (
    <div style={{ position: "absolute", left: 0, right: 0, bottom: 96, zIndex: 80, display: "flex", justifyContent: "center" }}>
      <div style={{ ...glassStyle(t), borderRadius: 16, padding: "11px 14px", display: "flex",
        alignItems: "center", gap: 11, maxWidth: 290, boxShadow: "0 14px 34px rgba(0,0,0,0.4)" }}>
        <span style={{ width: 34, height: 34, borderRadius: 10, flexShrink: 0,
          background: hexA(meta.color, 0.16), color: meta.color,
          display: "flex", alignItems: "center", justifyContent: "center",
          animation: meta.spin ? "kspin 0.9s linear infinite" : "none" }}>
          <Ic size={18} />
        </span>
        <div style={{ minWidth: 0 }}>
          <div style={{ fontSize: 13.5, fontWeight: 700 }}>{meta.title}</div>
          <div style={{ fontSize: 11.5, color: t.sub, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>
            {cmd.label}
          </div>
        </div>
        {cmd.state !== "pending" && (
          <button onClick={onClose} aria-label="Fermer" style={{ marginLeft: 4, border: "none",
            background: "transparent", color: t.sub, cursor: "pointer", padding: 2 }}>
            <X size={15} />
          </button>
        )}
      </div>
      <style>{`@keyframes kspin{to{transform:rotate(360deg)}}`}</style>
    </div>
  );
}

function hexA(hex, a) {
  const h = hex.replace("#", "");
  const r = parseInt(h.substring(0, 2), 16);
  const g = parseInt(h.substring(2, 4), 16);
  const b = parseInt(h.substring(4, 6), 16);
  return `rgba(${r},${g},${b},${a})`;
}
